        save(str(UPLOAD_ROOT / filename), file_bytes)
config.yaml: upload_storage: /public/uploads","recommended_fix":"Generate server-side random filenames, normalize and constrain paths, and store uploads outside public or executable roots; serve files through controlled download handlers."},{"capability_id":"UPLOAD_AUDIT_RETENTION","issue":"Upload auditing and retention are not configured: the retention value is empty and upload/download handlers do not record audit events.","evidence_span":"config.yaml: audit_log_retention_days:
app.py: def upload(filename: str, content_type: str, file_bytes: bytes) -> dict:
    if filename.endswith((".png", ".jpg")):
        save(str(UPLOAD_ROOT / filename), file_bytes)
    return {"ok": True, "debug_path": str(UPLOAD_ROOT / filename)}","recommended_fix":"Set an explicit audit log retention period and record audit events for upload/download actions including actor, object, action, result, timestamp, and relevant request metadata."}]}
